CREATE TABLE bigid_dstype_system_type_mappings (
id serial,
bigid_datasource_type character varying (255) NOT NULL,
system_type systemtype default null,
CONSTRAINT pk_bigid_dstype_system_type_mappings PRIMARY KEY (id)
);

CREATE UNIQUE INDEX ui_bigid_dstype_system_type_mappings_on_bigid_datasource_type ON
bigid_dstype_system_type_mappings (bigid_datasource_type);
